tinymce.PluginManager.add("latex", function (editor, url) {
    const normalizePluginUrl = (pluginUrl) => {
        const value = String(pluginUrl || "").replace(/\/+$/, "");
        if (/^https?:\/\//i.test(value) || value.startsWith("//")) return value;

        const baseUrl = String(editor?.editorManager?.baseURL || tinymce?.baseURL || "").replace(/\/+$/, "");
        if (!baseUrl) return value;

        try {
            const base = new URL(`${baseUrl}/`, window.location.href);

            if (value.startsWith("/")) {
                const basePath = base.pathname.replace(/\/+$/, "");
                if (value === `${basePath}/plugins/latex` || value.startsWith(`${basePath}/plugins/latex/`)) {
                    return new URL(value, base.origin).href.replace(/\/+$/, "");
                }

                if (value === "/plugins/latex" || value.startsWith("/plugins/latex/")) {
                    return new URL(value.replace(/^\/+/, ""), base.href).href.replace(/\/+$/, "");
                }

                return new URL(value, base.origin).href.replace(/\/+$/, "");
            }

            return new URL(value, base.href).href.replace(/\/+$/, "");
        } catch (error) {
            return `${baseUrl}/${value.replace(/^\/+/, "")}`.replace(/\/+$/, "");
        }
    };

    const openDialog = () => {
        const pluginBase = normalizePluginUrl(url);
        const dialogBase = `${pluginBase}/latex-dialog/`;
        return editor.windowManager.openUrl({
            title: "数学公式",
            url: `${dialogBase}index.html?dialogBase=${encodeURIComponent(dialogBase)}`,
            width: 1200,
            height: 800,
        });
    };

    // 注册一个工具栏按钮名称
    editor.ui.registry.addButton("latex", {
        // icon : 'latex',
        text: "Σ",
        tooltip: "插入Latex",
        onAction: function () {
            openDialog();
        },
    });

    window.addEventListener("message", (e) => {
        if (e.data?.source !== "tinymce-latex") return;

        if (e.data.type === "insert") {
            editor.insertContent(`<pre class="e-latex-area w-latex">${e.data.payload.latex}</pre>`);
            editor.windowManager.close();
        }

        if (e.data.type === "close") {
            editor.windowManager.close();
        }
    });

    // 注册一个菜单项名称 menu/menubar
    // editor.ui.registry.addMenuItem("latex", {
    //     text: "Example菜单名",
    //     onAction: function () {
    //         openDialog();
    //     },
    // });

    return {
        getMetadata: function () {
            return {
                //插件名和链接会显示在“帮助”→“插件”→“已安装的插件”中
                name: "latex", //插件名称
                url: "https://github.com/iRuxu", //作者网址
            };
        },
    };
});
